SELECT transmitter_name
FROM transmitters
WHERE manufacturer = 'Acme Inc.';

SELECT config_id, MAX(change_date) AS latest_change_date
FROM config_history
GROUP BY config_id;

SELECT MAX(change_date) 
FROM config_history 
WHERE config_id = 0;

SELECT receiver_name
FROM receivers
WHERE location = 'Factory A, Line 1';
